import { fetchAPI, getStrapiMedia } from '@/lib/api';
import Link from 'next/link';

export const revalidate = 3600;

export const metadata = {
    title: 'Blog | WeGovNYC',
    description: 'Updates and news from WeGovNYC',
};

async function getArticles() {
    try {
        const response = await fetchAPI('/articles?populate=image&sort=originalPublishDate:desc');
        return response.data || [];
    } catch (error) {
        console.error('Error fetching articles:', error);
        return [];
    }
}

function formatDate(dateString) {
    if (!dateString) return '';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
        year: 'numeric',
        month: 'long',
        day: 'numeric',
    });
}

export default async function BlogPage() {
    const articles = await getArticles();

    return (
        <div className="blog-page">
            <section className="blog-hero">
                <div className="blog-hero-content">
                    <h1>Blog</h1>
                    <p className="blog-hero-subtitle">
                        Updates, tutorials, and news from WeGovNYC
                    </p>
                </div>
            </section>

            <section className="blog-grid-section">
                <div className="blog-grid">
                    {articles.length === 0 ? (
                        <p className="no-articles">No articles found.</p>
                    ) : (
                        articles.map((article) => {
                            const imageUrl = article.image?.url
                                ? getStrapiMedia(article.image.url)
                                : null;

                            return (
                                <article key={article.id} className="blog-card">
                                    <Link href={`/blog/${article.slug}`} className="blog-card-link">
                                        {imageUrl ? (
                                            <div className="blog-card-image">
                                                {/* eslint-disable-next-line @next/next/no-img-element */}
                                                <img src={imageUrl} alt={article.title} />
                                            </div>
                                        ) : (
                                            <div className="blog-card-image blog-card-image-placeholder">
                                                <span>WeGovNYC</span>
                                            </div>
                                        )}
                                        <div className="blog-card-content">
                                            <h2 className="blog-card-title">{article.title}</h2>
                                            <div className="blog-card-meta-tags">
                                                {article.category && (
                                                    <span className="blog-card-category">{article.category}</span>
                                                )}
                                                {article.tags && article.tags.length > 0 && (
                                                    article.tags.map((tag, idx) => (
                                                        <span key={idx} className="blog-card-tag">{tag}</span>
                                                    ))
                                                )}
                                            </div>
                                            <div className="blog-card-meta">
                                                {article.author && (
                                                    <span className="blog-card-author">{article.author}</span>
                                                )}
                                                <time className="blog-card-date">
                                                    {formatDate(article.originalPublishDate)}
                                                </time>
                                            </div>
                                            {article.description && (
                                                <p className="blog-card-excerpt">{article.description}</p>
                                            )}
                                        </div>
                                    </Link>
                                </article>
                            );
                        })
                    )}
                </div>
            </section>
        </div>
    );
}
